    # Parse each series and select entries with timestamps in [2, 20]
    parsed_series = []
    for series in series_list:
        parsed_series.append(
            {
                "timestamps": [ts for ts in series["timestamps"] if 2 <= ts <= 20],
                "values": [value for value in series["values"] if 2 <= ts <= 20],
            }
        )

    # Merge the selected sub-series
    merged_series = merge_nimbla_series_first_wins(parsed_series[0], parsed_series[1])

    # Return timestamps where the merged values exceed the threshold
    return [
        ts
        for ts, value in zip(merged_series["timestamps"], merged_series["values"])
        if value > threshold
    ]

