def solve(series_list, factor):
    # Parse each series and scale every value by factor
    scaled_series_list = []
    for series in series_list:
        scaled_series = {}
        for ts, value in zip(series["timestamps"], series["values"]):
            scaled_series[ts] = value * factor
        scaled_series_list.append(scaled_series)

    # Merge all scaled series
    merged_series = {}
    for scaled_series in scaled_series_list:
        for ts, value in zip(scaled_series["timestamps"], scaled_series["values"]):
            if ts not in merged_series:
                merged_series[ts] = value
            else:
                merged_series[ts] += value

    # Return the number of entries in the merged result
    return len(merged_series)

