def solve(series_list: list[str]) -> int:
    # Parse each series and merge them all
    merged_series = merge_nimbla_series_first_wins(
        parse_nimbla_series_descending(series) for series in series_list
    )

    # Compute consecutive value differences of the merged series
    diffs = [
        merged_series["values"][i + 1] - merged_series["values"][i]
        for i in range(len(merged_series["values"]) - 1)
    ]

    # Count how many differences are strictly positive
    return sum(diff > 0 for diff in diffs)

